import{_ as e,o as l,c as a,a2 as d}from"./chunks/framework.Pywvta2k.js";const y=JSON.parse('{"title":"实战案例：男性阳虚寒湿型辨证全案","description":"","frontmatter":{},"headers":[],"relativePath":"tcm-data/08-实战案例/01-普光辨证案例.md","filePath":"tcm-data/08-实战案例/01-普光辨证案例.md","lastUpdated":1781084559000}'),i={name:"tcm-data/08-实战案例/01-普光辨证案例.md"};function r(n,t,s,g,x,h){return l(),a("div",null,[...t[0]||(t[0]=[d('<h1 id="实战案例-男性阳虚寒湿型辨证全案" tabindex="-1">实战案例：男性阳虚寒湿型辨证全案 <a class="header-anchor" href="#实战案例-男性阳虚寒湿型辨证全案" aria-label="Permalink to &quot;实战案例：男性阳虚寒湿型辨证全案&quot;">​</a></h1><blockquote><p>案例编号：CASE-TEMPLATE-M-001 辨证依据：黄元御《四圣心源》+ 彭子益《圆运动的古中医学》 本案例为水寒土湿木郁型的标准辨证模板</p></blockquote><hr><h2 id="一、患者信息" tabindex="-1">一、患者信息 <a class="header-anchor" href="#一、患者信息" aria-label="Permalink to &quot;一、患者信息&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;">性别</td><td style="text-align:left;">男</td></tr><tr><td style="text-align:left;">年龄</td><td style="text-align:left;">40-50岁区间</td></tr><tr><td style="text-align:left;">体型</td><td style="text-align:left;">偏胖/肌肉松软</td></tr><tr><td style="text-align:left;">体质倾向</td><td style="text-align:left;">脾肾阳虚型</td></tr></tbody></table><blockquote><p><strong>说明</strong>：本案例为典型阳虚寒湿体质辨证模板，具体四诊资料见正文。</p></blockquote><hr><h2 id="二、症状汇总-按系统" tabindex="-1">二、症状汇总（按系统） <a class="header-anchor" href="#二、症状汇总-按系统" aria-label="Permalink to &quot;二、症状汇总（按系统）&quot;">​</a></h2><h3 id="中焦-脾胃-系统" tabindex="-1">中焦（脾胃）系统 <a class="header-anchor" href="#中焦-脾胃-系统" aria-label="Permalink to &quot;中焦（脾胃）系统&quot;">​</a></h3><ul><li>面色暗沉如覆尘土（土色外现）</li><li>腹部及腰部畏凉喜暖</li><li>腰部赘肉、皮肤暗沉</li><li>身体沉重、倦怠无力</li><li>头颈部不自觉前倾</li></ul><h3 id="肝系统" tabindex="-1">肝系统 <a class="header-anchor" href="#肝系统" aria-label="Permalink to &quot;肝系统&quot;">​</a></h3><ul><li>目干涩、迎风流泪（劳倦后加重）</li><li>头发早白、枯槁</li><li>偶有抽筋（以前发作）</li><li>胁肋部偶有不适</li></ul><h3 id="相火-上热下寒-系统" tabindex="-1">相火（上热下寒）系统 <a class="header-anchor" href="#相火-上热下寒-系统" aria-label="Permalink to &quot;相火（上热下寒）系统&quot;">​</a></h3><ul><li>血压偏高（140/100区间）</li><li>前胸出汗多、后背少</li><li>口渴不贪凉</li><li>喜露腿脚入睡</li><li>鼻中生疮（春季多发）</li></ul><h3 id="下焦-水湿-系统" tabindex="-1">下焦（水湿）系统 <a class="header-anchor" href="#下焦-水湿-系统" aria-label="Permalink to &quot;下焦（水湿）系统&quot;">​</a></h3><ul><li>阴囊/腹股沟潮湿</li><li>臀部反复生疖</li><li>膝关节阴雨天疼痛</li><li>足跟皮肤开裂</li><li>足底蜕皮发痒</li></ul><hr><h2 id="三、病机分析" tabindex="-1">三、病机分析 <a class="header-anchor" href="#三、病机分析" aria-label="Permalink to &quot;三、病机分析&quot;">​</a></h2><p><strong>水寒土湿木郁 → 相火不降 → 上热下寒</strong></p><table tabindex="0"><thead><tr><th style="text-align:left;">层次</th><th style="text-align:left;">病机</th><th style="text-align:left;">症状证据</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>本</strong></td><td style="text-align:left;">脾肾阳虚、土湿水寒</td><td style="text-align:left;">腰腹凉、面色暗沉、无力</td></tr><tr><td style="text-align:left;"><strong>标</strong></td><td style="text-align:left;">肝郁化火、相火不降</td><td style="text-align:left;">血压高、口渴、前胸出汗</td></tr><tr><td style="text-align:left;"><strong>变</strong></td><td style="text-align:left;">湿热下注、瘀血内停</td><td style="text-align:left;">阴囊湿、足跟裂</td></tr></tbody></table><p><strong>核心辨证要点</strong>：</p><ul><li>本虚标实：脾肾阳虚为本，上热下寒为标</li><li>水湿贯穿三焦：上则相火不降（高血压），中则土湿（面色沉），下则水湿（阴囊湿）</li><li>治疗当以温阳化湿为主，不可见热清热</li></ul><hr><h2 id="四、主方-温潜黄芽天魂汤-加味" tabindex="-1">四、主方：温潜黄芽天魂汤（加味） <a class="header-anchor" href="#四、主方-温潜黄芽天魂汤-加味" aria-label="Permalink to &quot;四、主方：温潜黄芽天魂汤（加味）&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">药物</th><th style="text-align:center;">剂量</th><th style="text-align:left;">功能</th></tr></thead><tbody><tr><td style="text-align:left;">人参</td><td style="text-align:center;">9g</td><td style="text-align:left;">补中气</td></tr><tr><td style="text-align:left;">炙甘草</td><td style="text-align:center;">6g</td><td style="text-align:left;">培土和中</td></tr><tr><td style="text-align:left;">茯苓</td><td style="text-align:center;">15g</td><td style="text-align:left;">泄湿燥土</td></tr><tr><td style="text-align:left;">干姜</td><td style="text-align:center;">10g</td><td style="text-align:left;">温脾阳</td></tr><tr><td style="text-align:left;">制附子</td><td style="text-align:center;">9g（先煎45min）</td><td style="text-align:left;">温肾阳</td></tr><tr><td style="text-align:left;">桂枝</td><td style="text-align:center;">9g</td><td style="text-align:left;">达肝木</td></tr><tr><td style="text-align:left;">白芍</td><td style="text-align:center;">10g</td><td style="text-align:left;">敛相火</td></tr><tr><td style="text-align:left;">当归</td><td style="text-align:center;">10g</td><td style="text-align:left;">养肝血</td></tr><tr><td style="text-align:left;">制首乌</td><td style="text-align:center;">12g</td><td style="text-align:left;">养肝乌发</td></tr><tr><td style="text-align:left;">生龙骨</td><td style="text-align:center;">15g（先煎）</td><td style="text-align:left;">潜阳安神</td></tr><tr><td style="text-align:left;">生牡蛎</td><td style="text-align:center;">15g（先煎）</td><td style="text-align:left;">潜阳安神</td></tr><tr><td style="text-align:left;">泽泻</td><td style="text-align:center;">9g</td><td style="text-align:left;">利湿</td></tr><tr><td style="text-align:left;">丹皮</td><td style="text-align:center;">9g</td><td style="text-align:left;">活血</td></tr><tr><td style="text-align:left;">黄柏</td><td style="text-align:center;">6g</td><td style="text-align:left;">清湿热</td></tr><tr><td style="text-align:left;">怀牛膝</td><td style="text-align:center;">10g</td><td style="text-align:left;">引火下行</td></tr></tbody></table><h3 id="煎服法" tabindex="-1">煎服法 <a class="header-anchor" href="#煎服法" aria-label="Permalink to &quot;煎服法&quot;">​</a></h3><p>附子、龙骨、牡蛎先煎45分钟 → 入余药再煎30分钟 → 二煎25分钟 → 合并分早晚两次温服</p><h3 id="调护要点" tabindex="-1">调护要点 <a class="header-anchor" href="#调护要点" aria-label="Permalink to &quot;调护要点&quot;">​</a></h3><ul><li>忌生冷寒凉、水果过量</li><li>宜温热饮食，姜枣茶日常饮用</li><li>适度活动，助阳气温通</li></ul><h3 id="疗程" tabindex="-1">疗程 <a class="header-anchor" href="#疗程" aria-label="Permalink to &quot;疗程&quot;">​</a></h3><p>先服7剂，观察反应后随证加减</p><hr><h2 id="五、预后判断" tabindex="-1">五、预后判断 <a class="header-anchor" href="#五、预后判断" aria-label="Permalink to &quot;五、预后判断&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">阶段</th><th style="text-align:left;">预期变化</th></tr></thead><tbody><tr><td style="text-align:left;">1-2周</td><td style="text-align:left;">湿浊渐化：阴囊潮湿减轻、身体轻快</td></tr><tr><td style="text-align:left;">2-4周</td><td style="text-align:left;">阳气渐复：腰转暖、精力好转、血压趋稳</td></tr><tr><td style="text-align:left;">1-3月</td><td style="text-align:left;">肝血渐充：目干涩改善、面色转润</td></tr><tr><td style="text-align:left;">3-6月</td><td style="text-align:left;">体质转变：体质逐步改善，相关指标优化</td></tr></tbody></table><hr><h2 id="六、加减法-随证化裁" tabindex="-1">六、加减法（随证化裁） <a class="header-anchor" href="#六、加减法-随证化裁" aria-label="Permalink to &quot;六、加减法（随证化裁）&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">兼证</th><th style="text-align:left;">加减</th></tr></thead><tbody><tr><td style="text-align:left;">头痛明显</td><td style="text-align:left;">加川芎9g、白芷6g</td></tr><tr><td style="text-align:left;">失眠多梦</td><td style="text-align:left;">加酸枣仁15g、远志6g</td></tr><tr><td style="text-align:left;">便秘</td><td style="text-align:left;">加肉苁蓉15g、当归加至15g</td></tr><tr><td style="text-align:left;">腹泻</td><td style="text-align:left;">干姜加至15g，加白术10g</td></tr><tr><td style="text-align:left;">腰痛甚</td><td style="text-align:left;">加杜仲15g、续断10g</td></tr><tr><td style="text-align:left;">夜尿频</td><td style="text-align:left;">加益智仁10g、覆盆子10g</td></tr></tbody></table><hr><p><em>本案例为温阳化湿型基本辨证模板。实际临床需结合舌脉，随证治之。</em></p>',39)])])}const f=e(i,[["render",r]]);export{y as __pageData,f as default};
